 1	import React, { FC } from 'react';
 2	
 3	import {
 4	  Button,
 5	  Divider,
 6	  FormFieldGroupExpandable,
 7	  FormFieldGroupHeader,
 8	} from '@patternfly/react-core';
 9	import { TrashIcon } from '@patternfly/react-icons';
10	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
11	import { NetworkPolicyPeer, NetworkPolicyRule } from '@utils/models';
12	import NetworkPolicyPeerIPBlock from '@views/networkpolicies/new/NetworkPolicyPeerIPBlock';
13	import NetworkPolicyPeerSelectors from '@views/networkpolicies/new/NetworkPolicyPeerSelectors';
14	import { NetworkPolicyEgressIngress } from '@views/networkpolicies/new/utils/types';
15	import { getPeerRuleTitle } from '@views/networkpolicies/new/utils/utils';
16	
17	type NetworkPolicyRuleConfigPanelRulePeerProps = {
18	  direction: NetworkPolicyEgressIngress;
19	  index: number;
20	  onChange: (rule: NetworkPolicyRule) => void;
21	  peer: NetworkPolicyPeer;
22	  policyNamespace: string;
23	  rule: NetworkPolicyRule;
24	};
25	const NetworkPolicyRuleConfigPanelRulePeer: FC<NetworkPolicyRuleConfigPanelRulePeerProps> = ({
26	  direction,
27	  index,
28	  onChange,
29	  peer,
30	  policyNamespace,
31	  rule,
32	}) => {
33	  const { t } = useNetworkingTranslation();
34	
35	  const removePeer = (idx: number) => {
36	    rule.peers = [...rule.peers.slice(0, idx), ...rule.peers.slice(idx + 1)];
37	    onChange(rule);
38	  };
39	
40	  const peerPanel = peer.ipBlock ? (
41	    <NetworkPolicyPeerIPBlock
42	      direction={direction}
43	      ipBlock={peer.ipBlock}
44	      onChange={(ipBlock) => {
45	        rule.peers[index].ipBlock = ipBlock;
46	        onChange(rule);
47	      }}
48	    />
49	  ) : (
50	    <NetworkPolicyPeerSelectors
51	      direction={direction}
52	      namespaceSelector={peer.namespaceSelector}
53	      onChange={(podSel, nsSel) => {
54	        rule.peers[index].podSelector = podSel;
55	        rule.peers[index].namespaceSelector = nsSel;
56	        onChange(rule);
57	      }}
58	      podSelector={peer.podSelector || []}
59	      policyNamespace={policyNamespace}
60	    />
61	  );
62	  return (
63	    <div className="form-group" key={peer.key}>
64	      <FormFieldGroupExpandable
65	        header={
66	          <FormFieldGroupHeader
67	            actions={
68	              <Button
69	                aria-label={t('Remove peer')}
70	                className="co-create-networkpolicy__remove-peer"
71	                data-test="remove-peer"
72	                onClick={() => removePeer(index)}
73	                type="button"
74	                variant="plain"
75	              >
76	                <TrashIcon />
77	              </Button>
78	            }
79	            titleText={{
80	              id: `peer-header-${index}`,
81	              text: getPeerRuleTitle(direction, peer),
82	            }}
83	          />
84	        }
85	        isExpanded
86	        toggleAriaLabel="Peer"
87	      >
88	        {peerPanel}
89	      </FormFieldGroupExpandable>
90	      <Divider />
91	    </div>
92	  );
93	};
94	
95	export default NetworkPolicyRuleConfigPanelRulePeer;

